// Compliant: Use decimal values for clarity
func configurePermissions() {
    // Clear decimal representation
    fileMode := 420 // Or use os.FileMode constants

    // Clear intention with decimal
    maxRetries := 8

    // Use decimal or hexadecimal for large numbers
    bufferSize := 1023 // Decimal
    // Or use hexadecimal if bit patterns matter:
    // bufferSize := 0x3FF

    // Clear decimal calculation
    timeout := 24 * time.Second
}

// Compliant: Use proper constants or clear decimal values
func getErrorCodes() []int {
    return []int{
        http.StatusOK,        // 200
        http.StatusNotFound,  // 404
        http.StatusInternalServerError, // 500
    }
}

// Compliant: When you need octal (like file permissions), be explicit
func setFilePermissions(filename string) error {
    // Use os constants for clarity
    return os.Chmod(filename, 0644) // Standard permission pattern

    // Or better yet, use named constants
    const filePermissions = 0644
    return os.Chmod(filename, filePermissions)
}

// Compliant: Use explicit base conversion when needed
func parsePermissions(octalStr string) (int64, error) {
    return strconv.ParseInt(octalStr, 8, 32) // Explicit base 8
}
